"use client";

import { ToggleGroup as ToggleGroupRoot, type ToggleGroupProps } from "./toggle-group";
import { ToggleGroupItem, type ToggleGroupItemProps } from "./toggle-group-item";

const ToggleGroup = Object.assign(ToggleGroupRoot, {
  Item: ToggleGroupItem,
});

export { ToggleGroup, type ToggleGroupProps };
export { ToggleGroupItem, type ToggleGroupItemProps };

"use client";

import { useCallback, useMemo, useRef, type ReactNode, type Ref, type KeyboardEvent as ReactKeyboardEvent } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { composeRefs } from "@/lib/compose-refs";
import {
  getEnabledSelectableCollectionItems,
  getSelectableCollectionItemValue,
  resolveSelectableCollectionItemValue,
  useSelectableCollection,
} from "@/lib/selectable-collection";
import { cn } from "@/lib/utils";
import { ToggleGroupContext, type ToggleGroupSelectionMode } from "./toggle-group-context";

interface ToggleGroupSingleProps {
  selectionMode?: "single" | undefined;
  value?: string | null;
  defaultValue?: string | null;
  onChange?: (value: string | null) => void;
}

interface ToggleGroupMultipleProps {
  selectionMode: "multiple";
  value?: readonly string[];
  defaultValue?: readonly string[];
  onChange?: (value: readonly string[]) => void;
}

interface ToggleGroupBaseProps {
  allowDeselect?: boolean;
  disabled?: boolean;
  size?: "sm" | "md";
  orientation?: "horizontal" | "vertical";
  wrap?: boolean;
  highlighted?: string | null;
  onHighlightChange?: (value: string | null) => void;
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  label?: string;
  "aria-labelledby"?: string;
  name?: string;
  className?: string;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export type ToggleGroupProps = ToggleGroupBaseProps & (ToggleGroupSingleProps | ToggleGroupMultipleProps);

function arraysEqual(a: readonly string[], b: readonly string[]): boolean {
  if (a === b) return true;
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false;
  }
  return true;
}

export function ToggleGroup(props: ToggleGroupProps) {
  const {
    allowDeselect = false,
    disabled = false,
    size = "sm",
    orientation = "horizontal",
    wrap = true,
    highlighted: controlledHighlighted,
    onHighlightChange,
    onNavigationBoundaryReached,
    onKeyDown,
    label,
    "aria-labelledby": ariaLabelledBy,
    name,
    className,
    children,
    ref,
  } = props;
  const selectionMode: ToggleGroupSelectionMode = props.selectionMode ?? "single";

  const containerRef = useRef<HTMLDivElement>(null);
  const { items, registerItem, unregisterItem } = useSelectableCollection(containerRef);

  const singleProps = selectionMode === "single" ? (props as ToggleGroupSingleProps) : null;
  const multipleProps = selectionMode === "multiple" ? (props as ToggleGroupMultipleProps) : null;

  const singleControlled = singleProps?.value;
  const singleDefault = singleProps?.defaultValue;
  const singleOnChange = singleProps?.onChange;

  const multipleControlled = multipleProps?.value;
  const multipleDefault = multipleProps?.defaultValue;
  const multipleOnChange = multipleProps?.onChange;

  const [singleValue, setSingleValue, isSingleControlled] = useControllableState<string | null>({
    value: singleControlled,
    defaultValue: singleDefault ?? null,
    onChange: singleOnChange,
  });
  useFormReset(containerRef, singleDefault ?? null, setSingleValue, !isSingleControlled && selectionMode === "single");

  const [multipleValue, setMultipleValue] = useControllableState<readonly string[]>({
    value: multipleControlled,
    defaultValue: multipleDefault ?? [],
    onChange: multipleOnChange,
  });

  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    defaultValue: null,
    onChange: onHighlightChange,
  });

  const usesButtonSemantics = selectionMode === "multiple" || allowDeselect;

  const isItemSelected = useCallback(
    (value: string): boolean => {
      if (selectionMode === "multiple") {
        return multipleValue.includes(value);
      }
      return singleValue === value;
    },
    [selectionMode, multipleValue, singleValue],
  );

  const handleValueChange = useCallback(
    (newValue: string | null) => {
      if (newValue === null) return;
      if (selectionMode === "multiple") {
        setMultipleValue((prev) => {
          const next = prev.includes(newValue)
            ? prev.filter((v) => v !== newValue)
            : [...prev, newValue];
          return arraysEqual(prev, next) ? prev : next;
        });
        return;
      }
      setSingleValue((prev) => (prev === newValue && allowDeselect) ? null : newValue);
    },
    [allowDeselect, selectionMode, setMultipleValue, setSingleValue],
  );

  const enabledItems = getEnabledSelectableCollectionItems(items, disabled);
  const validHighlightedValue = getSelectableCollectionItemValue(enabledItems, highlightedValue);
  const focusAnchorValue = selectionMode === "single" ? singleValue : null;
  const tabTargetValue = resolveSelectableCollectionItemValue(enabledItems, highlightedValue, focusAnchorValue);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: usesButtonSemantics ? "button" : "radio",
    orientation,
    wrap,
    moveFocus: true,
    upKeys: ["ArrowUp", "ArrowLeft"],
    downKeys: ["ArrowDown", "ArrowRight"],
    highlighted: tabTargetValue,
    enabled: !disabled,
    onHighlightChange: usesButtonSemantics ? setHighlightedValue : handleValueChange,
    onNavigationBoundaryReached,
    scopeToContainer: true,
    ownerSelector: usesButtonSemantics ? '[data-diffgazer-selectable-owner="toggle"]' : undefined,
  });

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    navKeyDown(e);
  };

  const contextValue = useMemo(() => ({
    selectionMode,
    isItemSelected,
    onChange: handleValueChange,
    onHighlightChange: setHighlightedValue,
    disabled,
    size,
    highlightedValue: validHighlightedValue,
    containerRef,
    usesButtonSemantics,
    tabTargetValue,
    registerItem,
    unregisterItem,
  }), [selectionMode, isItemSelected, handleValueChange, setHighlightedValue, disabled, size, validHighlightedValue, usesButtonSemantics, tabTargetValue, registerItem, unregisterItem]);

  const renderHiddenInput = selectionMode === "single" && name && singleValue != null;

  return (
    <ToggleGroupContext value={contextValue}>
      <div
        ref={composeRefs(containerRef, ref)}
        role={usesButtonSemantics ? "group" : "radiogroup"}
        data-diffgazer-selectable-owner={usesButtonSemantics ? "toggle" : "radio"}
        aria-label={label}
        aria-labelledby={ariaLabelledBy}
        aria-orientation={usesButtonSemantics ? undefined : orientation}
        aria-disabled={disabled || undefined}
        onKeyDown={handleKeyDown}
        className={cn(
          "flex",
          orientation === "vertical" ? "flex-col gap-1.5" : "gap-1.5",
          wrap && orientation === "horizontal" && "flex-wrap",
          className,
        )}
      >
        {renderHiddenInput && (
          <input type="hidden" name={name} value={singleValue ?? ""} disabled={disabled} />
        )}
        {children}
      </div>
    </ToggleGroupContext>
  );
}

"use client";

import { createContext, useContext, type RefObject } from "react";

export type ToggleGroupSelectionMode = "single" | "multiple";

export interface ToggleGroupContextValue {
  selectionMode: ToggleGroupSelectionMode;
  isItemSelected: (value: string) => boolean;
  onChange: (value: string) => void;
  onHighlightChange: (value: string | null) => void;
  disabled: boolean;
  size: "sm" | "md";
  highlightedValue: string | null;
  containerRef: RefObject<HTMLDivElement | null>;
  usesButtonSemantics: boolean;
  tabTargetValue: string | null;
  registerItem: (itemId: string, value: string, disabled: boolean, element: HTMLElement | null) => void;
  unregisterItem: (itemId: string) => void;
}

export const ToggleGroupContext = createContext<ToggleGroupContextValue | undefined>(undefined);

export function useToggleGroupContext() {
  const context = useContext(ToggleGroupContext);
  if (!context) {
    throw new Error("ToggleGroup.Item must be used within ToggleGroup");
  }
  return context;
}

"use client";

import {
  type ComponentPropsWithRef,
  type FocusEvent,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  useId,
  useLayoutEffect,
  useRef,
} from "react";
import { cva } from "class-variance-authority";
import { useToggleGroupContext } from "./toggle-group-context";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";

const toggleItemVariants = cva(
  "inline-flex items-center justify-center font-mono whitespace-nowrap transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background cursor-pointer border border-border bg-transparent text-foreground hover:bg-secondary data-[active=true]:bg-primary data-[active=true]:text-primary-foreground data-[active=true]:border-primary data-[active=true]:hover:bg-primary/90",
  {
    variants: {
      size: {
        sm: "min-h-[44px] min-w-[44px] px-2 py-0.5 text-xs",
        md: "h-9 px-4 py-2 text-sm",
      },
    },
    defaultVariants: { size: "md" },
  },
);

export interface ToggleGroupItemProps
  extends Omit<ComponentPropsWithRef<"button">, "children" | "disabled" | "value"> {
  value: string;
  count?: number;
  disabled?: boolean;
  children: ReactNode;
}

export function ToggleGroupItem({
  value,
  count,
  disabled,
  className,
  children,
  ref,
  onClick,
  onKeyDown,
  onMouseEnter,
  onFocus,
  ...props
}: ToggleGroupItemProps) {
  const context = useToggleGroupContext();
  const itemId = useId();
  const rootRef = useRef<HTMLButtonElement>(null);
  const isActive = context.isItemSelected(value);
  const isHighlighted = context.highlightedValue === value;
  const isDisabled = context.disabled || !!disabled;
  const isTabTarget = !isDisabled && context.tabTargetValue === value;
  const { registerItem, unregisterItem } = context;

  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !isDisabled) context.onChange(value);
  };

  const handleKeyDown = (event: KeyboardEvent<HTMLButtonElement>) => {
    onKeyDown?.(event);
    if (
      !event.defaultPrevented &&
      context.usesButtonSemantics &&
      !isDisabled &&
      (event.key === "Enter" || event.key === " ")
    ) {
      event.preventDefault();
      context.onChange(value);
    }
  };

  const handleFocus = (event: FocusEvent<HTMLButtonElement>) => {
    onFocus?.(event);
    if (!event.defaultPrevented && !isDisabled) context.onHighlightChange(value);
  };

  useLayoutEffect(() => {
    registerItem(itemId, value, disabled === true, rootRef.current);
    return () => unregisterItem(itemId);
  }, [registerItem, unregisterItem, itemId, value, disabled]);

  return (
    <button
      {...props}
      ref={composeRefs(rootRef, ref)}
      type="button"
      role={context.usesButtonSemantics ? undefined : "radio"}
      data-value={value}
      data-diffgazer-navigation-item={context.usesButtonSemantics ? "button" : "radio"}
      data-active={isActive || undefined}
      data-highlighted={isHighlighted || undefined}
      aria-checked={context.usesButtonSemantics ? undefined : isActive}
      aria-pressed={context.usesButtonSemantics ? isActive : undefined}
      aria-disabled={isDisabled || undefined}
      disabled={isDisabled}
      tabIndex={isTabTarget ? 0 : -1}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      onMouseEnter={onMouseEnter}
      onFocus={handleFocus}
      className={cn(
        toggleItemVariants({ size: context.size }),
        isDisabled && "pointer-events-none opacity-50",
        isHighlighted && !isActive && "bg-secondary",
        className,
      )}
    >
      {count != null ? (
        <>
          [{children} {count}]
        </>
      ) : (
        children
      )}
    </button>
  );
}
